#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=20010,M=2e5+10;
struct Graph
{
	int head[N],des[M],nxt[M],cnt;
	inline void ins(int x,int y){nxt[++cnt]=head[x];des[cnt]=y;head[x]=cnt;}
	inline void Init(){memset(head,0,sizeof(head));cnt=1;}
}a,b;
int n,m,dfn[N],low[N],dcc[N],dep,cnt,siz[N],ans,mxd,S,lve[N],nlv,num;
bool vis[N],isc[M];
inline void tarjan(int u,int fa)
{
	
	dfn[u]=low[u]=++dep;grep(a,u,i)if(i^fa)
	{
		int v=a.des[i];if(!dfn[v])
		{
			tarjan(v,i^1);low[u]=min(low[u],low[v]);
			if(dfn[u]<low[v])isc[i]=isc[i^1]=1;
		}
		else low[u]=min(low[u],dfn[v]);
	}
}
inline void dfs0(int u){++siz[dcc[u]=cnt];grep(a,u,i)if(!isc[i]&&!dcc[a.des[i]])dfs0(a.des[i]);}//DCCcolor
inline void dfs1(int u)//Find Leaves
{
	bool flag=0;vis[u]=1;
	grep(b,u,i){int v=b.des[i];if(!vis[v]){dfs1(v);flag=1;}}
	if(!flag)lve[u]=1,++nlv;
}
inline void dfs2(int u,int fa,int dep)//find D
{
	vis[u]=1;if(dep>mxd){S=u;mxd=dep;}
	grep(b,u,i){int v=b.des[i];if(v^fa&&!lve[v])dfs2(v,u,dep+1);}
}
int main()
{
	a.Init();n=read(),m=read();rep(1,m,i){int x=read(),y=read();a.ins(x,y);a.ins(y,x);}
	rep(1,n,i)if(!dfn[i])tarjan(i,0);rep(1,n,i)if(!dcc[i])++cnt,dfs0(i);
//	rep(1,n,i)printf("%d ",dcc[i]);puts("");rep(2,a.cnt,i)printf("%d ",isc[i]);puts("");
	rep(1,n,u)grep(a,u,i){int v=a.des[i];if(dcc[u]^dcc[v])b.ins(dcc[u],dcc[v]);}
	rep(1,cnt,i)if(!vis[i]){++num;dfs1(i);int tmp=0;grep(b,i,j)++tmp;if(tmp==1)lve[i]=1,++nlv;};
	memset(vis,0,sizeof(vis));
//	rep(1,cnt,i)grep(b,i,j)printf("%d' %d'\n",i,b.des[j]);rep(1,cnt,i)printf("%d ",lve[i]);puts("");
	rep(1,cnt,i)if(!vis[i]&&!lve[i]){S=mxd=0;dfs2(i,0,1);mxd=0;dfs2(S,0,1);ans+=mxd;}
	int res=0;rep(1,cnt,i)res+=siz[i];printf("%d\n",res-ans-nlv+num-1);
}
